// HTML der Benachrichtigungsseite
const html = $('🌐 /benachrichtigung/ abrufen').first().json.data || '';

// Event-IDs: Suche /ticket_management, dann Event-ID rückwärts extrahieren
const eventIds = [];
const blocks = html.split('notification-object-type=');
for (const block of blocks) {
  if (!block.startsWith('"event_registration"')) continue;
  const chunk = block.substring(0, 2000);
  // Suche '/ticket_management' und gehe rückwärts zur Event-ID
  const tmIdx = chunk.indexOf('/ticket_management');
  if (tmIdx < 0) continue;
  // Vor '/ticket_management' steht: /event/1829501
  const before = chunk.substring(0, tmIdx);
  const lastSlash = before.lastIndexOf('/');
  if (lastSlash < 0) continue;
  const eventId = before.substring(lastSlash + 1);
  if (eventId && !isNaN(Number(eventId)) && eventId.length > 3) eventIds.push(eventId);
}
const uniqueIds = [...new Set(eventIds)];

if (uniqueIds.length === 0) {
  console.log('Keine event_registration Benachrichtigungen gefunden.');
  return [];
}

console.log('Event-IDs:', uniqueIds.join(', '));
return uniqueIds.map(id => ({ json: { eventId: id } }));

// Alle gefundenen Profile aus CDP + bereits bekannte aus NocoDB
const profiles = $input.item.json.profiles || [];
const existingRaw = $('📋 Bestehende Kandidaten laden').first().json.list || [];
const existingUrls = new Set(existingRaw.map(r => r.ProfilUrl).filter(Boolean));
const eventName = $input.item.json.pageInfo?.title || '';

const newUrls = profiles.filter(url => !existingUrls.has(url));

if (newUrls.length === 0) {
  console.log('Keine neuen Profile für Event', $input.item.json.event_id);
  return [];
}

console.log(`${newUrls.length} neue Profile: ${newUrls.join(', ')}`);
return newUrls.map(url => ({ json: { ProfilUrl: url, Status: 'neu', EventName: eventName } }));

